var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"도, 도시 외곽에서 저희의 진입을 막고 있던 핀리 하이어드의 부대가 퇴각했습니다!","JPN":"と、都市近郊で私たちの進入を阻んでいたフィンリー・ハイアードの部隊が退却しました！","ENG":"The Finley Hired unit that blocked our entry has retreated from the city perimeters!","TWN":"在、在城外阻攔我們的芬利傭兵團撤退了！！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"이제 관리국 재건도시 KS-1 상공으로 진입이 가능합니다.","JPN":"これで管理局の再建都市KS-1の上空に進入できます。","ENG":"We can now enter the airspace above the Administration Rebuilt City KS-1.","TWN":"現在，我們可以進入管理局重建城市KS-1上空了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그, 그런데 같은 민간군사기업을 공격하다니 이래도 되는 건가요?","JPN":"し、しかし同じ民間軍事企業を攻撃するなんて、問題ないのでしょうか？","ENG":"But... Are you sure we can just attack another PMC like this?","TWN":"但、但攻擊和我們同樣的民間軍事企業，這樣也沒問題嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"걱정 마세요, 레나 양.","JPN":"心配無用よ、レナさん。","ENG":"Don't worry, Lena.","TWN":"別擔心，蕾娜小姐。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"태스크포스 컴퍼니에게 중요한 것은 첫째도 고객, 둘째도 고객입니다.","JPN":"コフィンカンパニーにとって大事なのは、1にも2にもお客様です。","ENG":"There are two things that matter most to a TASKFORCE company. First: The customer. Second: The customer.","TWN":"對特遣勢力公司來說，最重要的第一是客戶，第二還是客戶。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"고객님께 가는 길을 막는 자들에게 자비심 따윈 필요 없습니다.","JPN":"お客様の元へ向かうのを邪魔する者なんて、憐れむ必要ありません。","ENG":"There's no need to show mercy to anyone who tries to stop us from reaching our customer!","TWN":"對擋住顧客去路的人，不需要有什麼慈悲之心。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"하, 하지만...... 도시관리국 항공 관제 센터에서도 미친 듯이 경고가 날아오고 있는데요?","JPN":"で、でも……都市管理局の航空管制センターからも警告メッセージが殺到していますよ？","ENG":"B-but... But the city's air traffic controller's been warning us non-stop!","TWN":"可、可是……城市管理局航空管制中心也瘋狂地對我們提出警告耶？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"절대 진입 금지라고....... 무단 진입 시 격추하겠다는데.......","JPN":"絶対に進入禁止だと……無断で進入すれば、撃墜すると言っているのですが……","ENG":"They're saying we are strictly restricted from entry... They even warned that they'd shoot us down if we proceed...","TWN":"他們說絕對禁止進入……擅自進入的話是會被擊落下來的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"해 보라죠.","JPN":"そんなの放っておけば良いのよ。","ENG":"Let them try.","TWN":"有種試試看啊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그따위 알량한 방공 시스템으로 저희 회사의 매출.......","JPN":"あんな粗悪な防空システムで、我が社の売上げを……","ENG":"If they think their petty air defense system is going to cut into our revenue...","TWN":"如果他們以為憑那種破爛的防空系統，就能打擊我們公司的營業額……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니, 의지를 꺾을 수 있을 거라고 생각하다니, 가소롭기 짝이 없군요.","JPN":"いや、意志が折れると思うなんて、馬鹿馬鹿しいわ。","ENG":"I mean, our morale... They've got another thing coming.","TWN":"不，是就能打擊我們的意志，那真是可笑至極。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아니, 그게 무슨......","JPN":"それはどういう……","ENG":"What do you mean...?","TWN":"什麼？妳說什麼……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"이거 완전 해적질 아닌......","JPN":"だって、これは海賊行為に等しい……","ENG":"We're no better than pirates!","TWN":"這完全就是單純的海盜……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RIFLE_SL_NULL_MEMBERS","face":"UNIT_IDLE"},"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":" 읍읍!","JPN":"んぐ！","ENG":" Mmff! Mff! Mmmf!","TWN":"唔唔！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RIFLE_SL_NULL_MEMBERS","face":"UNIT_IDLE"},"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오늘은 레나 양의 건강 상태가 나빠 보이네요.","JPN":"今日はどうもレナさんの体調があまり優れないようですね。","ENG":"Lena? You're looking a bit under the weather...","TWN":"今天蕾娜小姐的健康狀況看起來不是很好。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"경호대, 레나 양을 치료실로 인계해 주세요.","JPN":"警護隊、レナさんを治療室に連れていってください。","ENG":"Guard, please take Lena to the infirmary.","TWN":"警衛隊，請將蕾娜小姐帶到醫療室去。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"읍읍읍!","JPN":"んぐぐ！","ENG":"Mmff! Mff!","TWN":"唔唔唔！！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RIFLE_SL_NULL_MEMBERS","face":"UNIT_IDLE"},"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};